PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (COUNT(?movie) AS ?count)
WHERE {
  ?movie wdt:P1367 wd:Q3627883 ;
         wdt:P577 ?release .
  FILTER (?release < "2022-01-01"^^xsd:date)
}

